WITH samsung_ship AS (SELECT CAST(s.asin AS TEXT) AS asin, MAX(s.item_name) AS item_name, SUM(s.shipped_units) AS shipped_units FROM shipped_raw s WHERE (s.brand_name ILIKE '%Samsung%' OR s.item_name ILIKE '%Samsung%') GROUP BY CAST(s.asin AS TEXT)), samsung_conc AS (SELECT CAST(c.asin AS TEXT) AS asin, SUM(c.conceded_units) AS conceded_units FROM concession_raw c JOIN shipped_raw s ON CAST(c.asin AS TEXT) = CAST(s.asin AS TEXT) AND c.mapped_year = s.year AND c.mapped_month = s.month AND c.mapped_week = s.week WHERE (c.brand_name ILIKE '%Samsung%' OR c.item_name ILIKE '%Samsung%') AND (s.brand_name ILIKE '%Samsung%' OR s.item_name ILIKE '%Samsung%') GROUP BY CAST(c.asin AS TEXT)) SELECT ss.asin, ss.item_name, ss.shipped_units, COALESCE(sc.conceded_units, 0) AS conceded_units, (COALESCE(sc.conceded_units, 0) * 100.0) / NULLIF(ss.shipped_units, 0) AS return_rate_pct FROM samsung_ship ss LEFT JOIN samsung_conc sc ON sc.asin = ss.asin WHERE ss.shipped_units > 0 ORDER BY return_rate_pct DESC NULLS LAST, conceded_units DESC, shipped_units DESC LIMIT 50;